/**
 * scripts/build-server-bundle.mjs
 *
 * server.ts(커스텀 HTTP + Socket.io 서버)를 esbuild 로 단일 JS 번들로 만들어
 * .next/standalone/unoworship-server.js 에 놓는다.
 *
 * - `next` 패키지는 external — standalone/node_modules 의 next 를 런타임에 사용.
 * - socket.io, atem-connection 등 server.ts 전용 의존성은 번들에 포함되므로
 *   standalone tracing 에 안 잡혀도 동작한다.
 * - Electron main 은 이 파일을 utilityProcess(내장 Node)로 직접 기동한다.
 *   사용자 컴퓨터에 Node/npm/tsx 설치가 필요 없다.
 *
 * 실행: npm run build:server  (반드시 `next build` 이후)
 */

import { build } from 'esbuild';
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const standaloneDir = path.join(root, '.next', 'standalone');
const outFile = path.join(standaloneDir, 'unoworship-server.js');

if (!fs.existsSync(standaloneDir)) {
  console.error(
    '[build:server] .next/standalone 이 없습니다. 먼저 `npm run build` 를 실행하세요 ' +
      '(next.config.ts 의 output: "standalone" 필요).'
  );
  process.exit(1);
}

await build({
  entryPoints: [path.join(root, 'server.ts')],
  outfile: outFile,
  bundle: true,
  platform: 'node',
  format: 'cjs',
  target: 'node20',
  // next 는 standalone/node_modules 에서 런타임 resolve (번들 불가·불필요)
  external: ['next'],
  sourcemap: false,
  logLevel: 'info',
});

// standalone 의 pruned next 패키지에는 루트 shim(next/server.js)이 없다.
// 원본 shim 은 ImageResponse/userAgent 등 traced 되지 않은 모듈까지 eager
// require 하므로 그대로 복사하면 또 MODULE_NOT_FOUND 가 난다.
// 서버 번들이 실제로 쓰는 NextRequest/NextResponse 만 내보내는 최소 shim 을 쓴다.
const shimDest = path.join(standaloneDir, 'node_modules', 'next', 'server.js');
fs.writeFileSync(
  shimDest,
  [
    '// generated by scripts/build-server-bundle.mjs — minimal next/server shim for standalone',
    "exports.NextRequest = require('next/dist/server/web/spec-extension/request').NextRequest;",
    "exports.NextResponse = require('next/dist/server/web/spec-extension/response').NextResponse;",
    '',
  ].join('\n'),
  'utf-8'
);
console.log('[build:server] 최소 next/server shim 생성');

// next/headers shim — 원본의 require 대상(dist/server/request/*)은 모두 traced
// 되어 있으므로 원본을 그대로 복사한다.
const headersSrc = path.join(root, 'node_modules', 'next', 'headers.js');
const headersDest = path.join(standaloneDir, 'node_modules', 'next', 'headers.js');
if (fs.existsSync(headersSrc)) {
  fs.copyFileSync(headersSrc, headersDest);
  console.log('[build:server] next/headers shim 복사');
}

console.log(`[build:server] OK → ${path.relative(root, outFile)}`);
